import React from "react";

const About = () => (
  <div style={{ padding: "40px" }}>
    <h2>About RealEstateHub</h2>
    <p>
      RealEstateHub is your trusted platform for buying, selling, and renting properties across India. We offer a wide range of listings, advanced search filters, and secure booking options.
    </p>
    <ul>
      <li>Verified properties</li>
      <li>Easy search and filter</li>
      <li>Secure user accounts</li>
      <li>Admin dashboard for agents</li>
    </ul>
  </div>
);

export default About;
